import org.junit.jupiter.api.Test;
import java.util.List;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void simpleUnquotedFields() {
        assertEquals(List.of("a", "b", "c"),
                new Solution().parseCsvLine("a,b,c"));
    }

    @Test
    void quotedFieldWithInternalComma() {
        // raw input: "a,b",c
        assertEquals(List.of("a,b", "c"),
                new Solution().parseCsvLine("\"a,b\",c"));
    }

    @Test
    void escapedDoubleQuoteInsideQuotedField() {
        // raw input: "he said ""hi""",end  →  he said "hi"
        assertEquals(List.of("he said \"hi\"", "end"),
                new Solution().parseCsvLine("\"he said \"\"hi\"\"\",end"));
    }

    @Test
    void emptyStringInput() {
        // empty string → one empty field
        assertEquals(List.of(""),
                new Solution().parseCsvLine(""));
    }

    @Test
    void commasOnlyThreeEmptyFields() {
        assertEquals(List.of("", "", ""),
                new Solution().parseCsvLine(",,"));
    }

    @Test
    void singleField() {
        assertEquals(List.of("hello"),
                new Solution().parseCsvLine("hello"));
    }

    @Test
    void twoEmptyFields() {
        assertEquals(List.of("", ""),
                new Solution().parseCsvLine(","));
    }
}
